import{_ as a,o as e,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Page/page-settings.md","filePath":"ms-MY/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"ms-MY/Page/page-settings.md"};function o(i,t,l,g,s,m){return e(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings mengawal site display, upload page defaults, background images dan admin panel appearance.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>Title yang dipaparkan dalam browser tab.</td></tr><tr><td>Site icon</td><td>Icon kecil yang dipaparkan dalam browser tab.</td></tr><tr><td>ImgBed name</td><td>Name yang dipaparkan pada frontend pages.</td></tr><tr><td>ImgBed logo</td><td>Logo image yang dipaparkan pada frontend pages.</td></tr><tr><td>Logo link</td><td>URL yang dibuka apabila klik logo atau avatar.</td></tr><tr><td>Background switch interval</td><td>Rotation interval untuk multiple backgrounds, dalam milliseconds. <code>60000</code> bermaksud 60 seconds.</td></tr><tr><td>Background opacity</td><td>Opacity background image dari <code>0</code> hingga <code>1</code>. Nilai lebih rendah kelihatan lebih ringan.</td></tr><tr><td>Default URL prefix</td><td>Prefix yang digunakan semasa generate image links. Kosong bermaksud current site domain digunakan.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>Announcement yang dipaparkan di bahagian atas upload page. HTML disokong.</td></tr><tr><td>Default upload channel</td><td>Upload channel yang dipilih secara default pada upload page. Anda juga boleh memilih Smart Dispatch.</td></tr><tr><td>Default upload directory</td><td>Default upload directory, contohnya <code>/user/</code>. Kosong atau <code>/</code> bermaksud root.</td></tr><tr><td>Default naming method</td><td>Default filename generation strategy selepas upload. Lihat di bawah.</td></tr><tr><td>Convert to WebP by default</td><td>Convert images kepada WebP sebelum upload.</td></tr><tr><td>Enable compression by default</td><td>Compress images secara local dalam browser sebelum upload.</td></tr><tr><td>Default compression threshold</td><td>Compress secara automatik apabila image melebihi saiz ini, dalam MB.</td></tr><tr><td>Default target size</td><td>Target file size selepas compression, dalam MB.</td></tr><tr><td>Login page background</td><td>Background image untuk user login page.</td></tr><tr><td>Upload page background</td><td>Background image untuk upload page.</td></tr><tr><td>Footer portal link</td><td>URL yang dibuka oleh footer portal button.</td></tr><tr><td>Hide footer</td><td>Menyembunyikan frontend footer apabila enabled.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>Background image untuk admin login page.</td></tr><tr><td>Admin background</td><td>Background image untuk admin pages. Gunakan satu image URL atau beberapa URLs.</td></tr><tr><td>Image loading mode</td><td>Preview loading mode untuk admin file list. Original load original images. Smart loading mengutamakan thumbnails untuk public images dan originals untuk restricted images.</td></tr><tr><td>Thumbnail source</td><td>Service untuk generate thumbnails: wsrv.nl, Cloudflare Image Resizing atau WordPress Photon. Cloudflare Image Resizing mesti enabled dalam Cloudflare sebelum dipilih.</td></tr><tr><td>Live2D widget</td><td>Memaparkan Live2D character dalam admin panel.</td></tr><tr><td>Firework click effect</td><td>Memaparkan firework effect apabila klik halaman.</td></tr><tr><td>Star cursor trail</td><td>Memaparkan star trail apabila mouse bergerak.</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background dan admin login background menyokong formats ini:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Menggunakan Bing wallpaper rotation.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Rotate beberapa images.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Menggunakan satu background image.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Menggunakan random image API link. Anda boleh configure Random Image API sendiri dalam Other Settings, kemudian paste generated random image link di sini sebagai single-background entry.</td></tr></tbody></table><p>Admin background menyokong image URLs. Beberapa URLs boleh dipisahkan dengan English commas seperti prompt pada halaman. Kosong bermaksud default background digunakan.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>Time-random prefix + original filename, contohnya <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>Time-random prefix dan extension sahaja, contohnya <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>Mengekalkan original filename, contohnya <code>cat.png</code>. Jika duplicate, ImgBed menambah <code>(1)</code>, <code>(2)</code> dan seterusnya.</td></tr><tr><td>Short link</td><td>Menggunakan 8-character short ID dan extension, contohnya <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const p=a(r,[["render",o]]);export{c as __pageData,p as default};
